import java.util.*; public class Solution { public static long run(List<String> rows) { long hash = 1469598103934665603L; for (String row : rows) { String[] parts = row.split(","); int b = parts[2].charAt(0) - '0'; int c = parts[3].charAt(0) - '0'; boolean hot = parts[4].charAt(0) == 'h'; long v = (b > 300 ? (b + c) : 0) + (hot ? 29 : 0); hash ^= (v + 1); hash *= 1099511628211L; } return hash; } }